import { isEqual } from 'lodash-es';

import { TooltipContext, useTooltip } from './contexts/TooltipContext.js';
import type { TooltipState } from './types.js';
import { useStoreSelector } from '../../../../core/store/selector.js';

export const useSelector = <S>(selector: (state: TooltipState) => S) =>
  useStoreSelector(TooltipContext, selector, isEqual);

export const useTooltipSnapshot = () => useTooltip().getState();
